  7→const { execSync } = require("child_process");
  8→
  9→/**
 10→ * Execute a shell command and return the output
 11→ * @param {string} command - Command to execute
 12→ * @returns {string} Command output
 13→ */
 14→function exec(command) {
 15→  try {
 16→    return execSync(command, {
 17→      encoding: "utf-8",
 18→      stdio: ["ignore", "pipe", "ignore"],
 19→      maxBuffer: 16 * 1024 * 1024,
 20→    }).trim();
 21→  } catch (error) {
 22→    console.error(`Error executing command: ${command}`);
 23→    console.error(error.message);
 24→    throw error;
 25→  }
 26→}
 27→
 28→/**
 29→ * Get dependencies for one or more crates using cargo tree
 30→ * @param {string | string[]} packages - Package name(s) to query
 31→ * @param {object} options - Additional options
 32→ * @param {string} [options.features] - Features to enable
 33→ * @param {boolean} [options.noDefaultFeatures] - Disable default features
 34→ * @returns {string[]} Array of dependency crate names (excluding the queried package(s))
 35→ */
 36→function getCrateDependencies(packages, options = {}) {
 37→  const pkgs = Array.isArray(packages) ? packages : [packages];
 38→  const packageArgs = pkgs.map((pkg) => `-p ${pkg}`).join(" ");
 39→
 40→  let command = `cargo tree ${packageArgs} -f '{lib}' -e normal --prefix none`;
 41→
 42→  if (options.features) {
 43→    command += ` --features ${options.features}`;
 44→  }
 45→
 46→  if (options.noDefaultFeatures) {
 47→    command += " --no-default-features";
 48→  }
 49→
 50→  const output = exec(command);
 51→
 52→  const deps = output
 53→    .split("\n")
 54→    .map((dep) => dep.replace(/\s+\(\*\)$/u, ""))
 55→    .filter((dep) => dep && dep.includes("oxc") && !pkgs.includes(dep));
 56→
 57→  if (deps.length === 0) {
 58→    console.error(`Warning: Could not get dependencies for ${pkgs.join(", ")}`);
 59→    return [];
 60→  }
 61→
 62→  return Array.from(new Set(deps)).sort();
 63→}
 64→
 65→/**
 66→ * Check if any changed files affect specified crates or paths
 67→ * @param {string[] | null} changedFiles - Array of changed file paths, or null
 68→ * @param {string[]} crates - Array of crate names to check
 69→ * @param {string[]} [additionalPaths] - Additional paths to check (e.g., 'tasks/benchmark/')
 70→ * @returns {boolean} True if any file affects the specified crates or paths
 71→ */
 72→function checkFilesAffectCrates(changedFiles, crates, additionalPaths = []) {
 73→  if (!changedFiles || changedFiles.length === 0) {
 74→    return false;
 75→  }
 76→
 77→  // Check if any changed file affects a crate
