 55→async function getChangedFiles() {
 56→  const eventName = process.env.GITHUB_EVENT_NAME;
 57→  const repository = process.env.GITHUB_REPOSITORY;
 58→  const sha = process.env.GITHUB_SHA;
 59→  const prNumber = process.env.GITHUB_PR_NUMBER;
 60→  const ref = process.env.GITHUB_REF;
 61→
 62→  console.error(`Event: ${eventName}`);
 63→  console.error(`Repository: ${repository}`);
 64→  console.error(`SHA: ${sha}`);
 65→  console.error(`Ref: ${ref}`);
 66→
 67→  if (eventName === "workflow_dispatch") {
 68→    console.error("Manual trigger - returning null (run all)");
 69→    return null; // Signal to run all
 70→  }
 71→
 72→  let files = [];
 73→
 74→  try {
 75→    if (eventName === "pull_request" && prNumber) {
 76→      // For PR, use GitHub API to get changed files
 77→      console.error(`Getting changed files for PR #${prNumber}`);
 78→      const prFiles = await githubApi(`/repos/${repository}/pulls/${prNumber}/files?per_page=100`);
 79→      files = prFiles.map((f) => f.filename);
 80→    } else if (sha && repository) {
 81→      // For push to main, get the commit and compare with parent
 82→      console.error(`Getting changed files for commit ${sha}`);
 83→      const commit = await githubApi(`/repos/${repository}/commits/${sha}`);
 84→      files = commit.files ? commit.files.map((f) => f.filename) : [];
 85→    } else {
 86→      // No valid parameters for API calls
 87→      console.error("Error: Missing required environment variables for GitHub API");
 88→      console.error("Returning null (run all) as fallback");
 89→      return null; // Signal to run all
 90→    }
 91→  } catch (error) {
 92→    console.error(`Error getting changed files via API: ${error.message}`);
 93→    console.error("Returning null (run all) as fallback");
 94→    return null; // Signal to run all
 95→  }
 96→
 97→  console.error(`Changed files (${files.length}):`);
 98→  files.forEach((f) => console.error(`  - ${f}`));
 99→
100→  return files;
101→}
102→
103→module.exports = { getChangedFiles };
