108→    .then((files) => {
109→      console.log(JSON.stringify(files));
110→      process.exit(0);
111→    })
112→    .catch((error) => {
113→      console.error("Error:", error);
114→      console.log(JSON.stringify(null));
115→      process.exit(1);
116→    });
117→}
