  1→#!/usr/bin/env node
  2→
  3→// oxlint-disable no-console
  4→
  5→/**
  6→ * Generic change detection script for CI jobs.
  7→ *
  8→ * Include mode (default): checks if changes affect specified crates or their transitive dependencies.
  9→ *   node check-changes.js --packages oxc_minifier --paths tasks/minsize/
 10→ *
 11→ * Exclude mode: skips only if ALL changed files belong to excluded crate directories.
 12→ *   node check-changes.js --exclude oxc_linter,oxc_language_server --paths napi/,npm/
 13→ */
 14→
 15→const { getChangedFiles } = require("./get-changed-files.js");
 16→const { getCrateDependencies, checkFilesAffectCrates } = require("./utils.js");
 17→
 18→/**
 19→ * Parse CLI arguments into structured options.
 20→ * @returns {{ packages: string[], exclude: string[], paths: string[] }}
 21→ */
 22→function parseArgs() {
 23→  const args = process.argv.slice(2);
 24→  const result = { packages: [], exclude: [], paths: [] };
 25→
 26→  for (let i = 0; i < args.length; i++) {
 27→    const arg = args[i];
 28→    if (arg === "--packages" && args[i + 1]) {
 29→      result.packages = args[++i].split(",").filter(Boolean);
 30→    } else if (arg === "--exclude" && args[i + 1]) {
 31→      result.exclude = args[++i].split(",").filter(Boolean);
 32→    } else if (arg === "--paths" && args[i + 1]) {
 33→      result.paths = args[++i].split(",").filter(Boolean);
 34→    }
 35→  }
 36→
 37→  return result;
 38→}
 39→
 40→/**
 41→ * Include mode: run if changes affect any of the specified crates (+ transitive deps) or paths.
 42→ * @param {string[] | null} changedFiles
 43→ * @param {string[]} packages - Root crate names
 44→ * @param {string[]} paths - Additional trigger paths
 45→ * @returns {boolean}
 46→ */
 47→function shouldRunInclude(changedFiles, packages, paths) {
 48→  if (changedFiles === null) {
 49→    console.error("No changed files list (manual trigger or error) - will run");
 50→    return true;
 51→  }
 52→
 53→  if (changedFiles.length === 0) {
 54→    console.error("No files changed - will skip");
 55→    return false;
 56→  }
 57→
 58→  // Resolve transitive dependencies via cargo tree
 59→  let allCrates;
 60→  try {
 61→    const deps = getCrateDependencies(packages);
 62→    allCrates = [...packages, ...deps];
 63→    console.error(`Checking crates (${allCrates.length}): ${allCrates.join(", ")}`);
 64→  } catch (error) {
 65→    console.error(`cargo tree failed: ${error.message} - will run as fallback`);
 66→    return true;
 67→  }
 68→
 69→  if (allCrates.length === 0) {
 70→    console.error("Warning: No crates resolved - will run as fallback");
 71→    return true;
 72→  }
 73→
 74→  return checkFilesAffectCrates(changedFiles, allCrates, paths);
 75→}
 76→
 77→/**
 78→ * Exclude mode: skip only if ALL changed files belong to excluded crate directories or paths.
 79→ * No cargo tree — exclusion is intentionally shallow.
 80→ * @param {string[] | null} changedFiles
 81→ * @param {string[]} excludeCrates - Crate names to exclude
 82→ * @param {string[]} paths - Additional paths that always trigger the job
 83→ * @returns {boolean}
 84→ */
 85→function shouldRunExclude(changedFiles, excludeCrates, paths) {
 86→  if (changedFiles === null) {
 87→    console.error("No changed files list (manual trigger or error) - will run");
 88→    return true;
 89→  }
 90→
 91→  if (changedFiles.length === 0) {
 92→    console.error("No files changed - will skip");
 93→    return false;
 94→  }
 95→
 96→  // Check always-trigger paths first
 97→  for (const file of changedFiles) {
 98→    for (const p of paths) {
 99→      if (file.startsWith(p)) {
100→        console.error(`File ${file} matches always-trigger path ${p} - will run`);
101→        return true;
102→      }
103→    }
104→  }
105→
106→  const excludePaths = excludeCrates.map((c) => `crates/${c}/`);
107→
108→  // Skip only if EVERY changed file is inside an excluded crate directory
109→  const allExcluded = changedFiles.every((file) =>
110→    excludePaths.some((ep) => file.startsWith(ep)),
111→  );
112→
113→  if (allExcluded) {
114→    console.error(
115→      `All ${changedFiles.length} changed files are in excluded crates (${excludeCrates.join(", ")}) - will skip`,
116→    );
117→    return false;
118→  }
119→
120→  console.error("Changes found outside excluded crates - will run");
121→  return true;
122→}
123→
124→async function main() {
125→  try {
126→    const opts = parseArgs();
127→
128→    if (opts.packages.length === 0 && opts.exclude.length === 0) {
129→      console.error("Error: must specify --packages or --exclude");
130→      console.log("true");
131→      process.exit(0);
132→    }
133→
134→    const changedFiles = await getChangedFiles();
135→
136→    let shouldRun;
137→    if (opts.exclude.length > 0) {
138→      shouldRun = shouldRunExclude(changedFiles, opts.exclude, opts.paths);
139→    } else {
140→      shouldRun = shouldRunInclude(changedFiles, opts.packages, opts.paths);
141→    }
142→
143→    console.log(shouldRun ? "true" : "false");
144→
145→    if (shouldRun) {
146→      console.error("::notice title=Change detection::Will run this job");
147→    } else {
148→      console.error("::notice title=Change detection::Will skip this job");
149→    }
150→
151→    process.exit(0);
152→  } catch (error) {
153→    console.error("Error in change detection:", error);
154→    // On error, run as a fallback
155→    console.log("true");
156→    console.error(
157→      "::warning title=Change detection error::Error occurred, running as fallback",
158→    );
159→    process.exit(0);
160→  }
161→}
162→
163→void main();
